def min_cost(costs, m, n):
    if m == 0 and n == 0:
        return costs[0][0]

    dp = [[0 for _ in range(n + 1)] for _ in range(m + 1)]

    dp[0][0] = costs[0][0]

    for i in range(1, m + 1):
        dp[i][0] = dp[i - 1][0] + costs[i][0]

    for j in range(1, n + 1):
        dp[0][j] = dp[0][j - 1] + costs[0][j]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + costs[i][j]

    return dp[m][n]
