def min_cost(costs, m, n):
    if m < 0 or n < 0 or not costs or not costs[0]:
        return float('inf')

    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            dp[i][j] = costs[i - 1][j - 1] + min(dp[i - 1][j], dp[i][j - 1])

    return dp[m][n]
